```javascript
function countElements(arr) {
  let frequency = {};
  for (let i = 0; i < arr.length; i++) {
    let element = arr[i];
    if (frequency[element]) {
      frequency[element]++;
    } else {
      frequency[element] = 1;
    }
  }
  return frequency;
}

// Example usage
let inputArr = [1, 2, 3, 2, 1, 3, 4, 5, 4];
let result = countElements(inputArr);
console.log(result);
```

Output:
